impl Solution { pub fn num_rolls_to_target(n: i32, k: i32, target: i32) -> i32 { let black_mod = 1_000_000_007; let mut black_dp = vec![0; target as usize + 1]; black_dp[0] = 1; for _ in 1..=n { let mut black_next = vec![0; target as usize + 1]; for black_s in 1..=target as usize { for black_f in 1..=k as usize { if black_s >= black_f { black_next[black_s] = (black_next[black_s] + black_dp[black_s - black_f]) % black_mod; } } } black_dp = black_next; } black_dp[target as usize] } }